
-- FUNCTIONS
CREATE OR REPLACE FUNCTION public.handle_new_user() RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$ BEGIN INSERT INTO public.profiles (id, name, email, premium_expires_at) VALUES (NEW.id, COALESCE(NEW.raw_user_meta_data->>'name', ''), NEW.email, now() + interval '14 days'); RETURN NEW; END; $$;
CREATE OR REPLACE FUNCTION public.update_updated_at_column() RETURNS trigger LANGUAGE plpgsql SET search_path TO 'public' AS $$ BEGIN NEW.updated_at = now(); RETURN NEW; END; $$;
CREATE OR REPLACE FUNCTION public.has_role(_user_id uuid, _role app_role) RETURNS boolean LANGUAGE sql STABLE SECURITY DEFINER SET search_path TO 'public' AS $$ SELECT EXISTS (SELECT 1 FROM public.user_roles WHERE user_id = _user_id AND role = _role); $$;
CREATE OR REPLACE FUNCTION public.is_turma_member(_user_id uuid, _turma_id uuid) RETURNS boolean LANGUAGE sql STABLE SECURITY DEFINER SET search_path TO 'public' AS $$ SELECT EXISTS (SELECT 1 FROM public.turma_members WHERE user_id = _user_id AND turma_id = _turma_id); $$;
CREATE OR REPLACE FUNCTION public.get_turma_role(_user_id uuid, _turma_id uuid) RETURNS turma_role LANGUAGE sql STABLE SECURITY DEFINER SET search_path TO 'public' AS $$ SELECT role FROM public.turma_members WHERE user_id = _user_id AND turma_id = _turma_id LIMIT 1; $$;
CREATE OR REPLACE FUNCTION public.has_turma_permission(_user_id uuid, _turma_id uuid, _permission text) RETURNS boolean LANGUAGE plpgsql STABLE SECURITY DEFINER SET search_path TO 'public' AS $$ DECLARE _role public.turma_role; _override BOOLEAN; BEGIN SELECT role INTO _role FROM public.turma_members WHERE user_id = _user_id AND turma_id = _turma_id; IF _role IS NULL THEN RETURN FALSE; END IF; IF _role = 'admin' THEN RETURN TRUE; END IF; SELECT granted INTO _override FROM public.turma_permissions WHERE turma_permissions.turma_id = _turma_id AND turma_permissions.user_id = _user_id AND turma_permissions.permission = _permission; IF _override IS NOT NULL THEN RETURN _override; END IF; IF _role = 'moderator' THEN RETURN _permission IN ('invite','create_subject','create_lesson','create_deck','create_exam'); END IF; RETURN _permission IN ('create_deck'); END; $$;
CREATE OR REPLACE FUNCTION public.get_marketplace_fee(tier integer) RETURNS numeric LANGUAGE sql IMMUTABLE SET search_path TO 'public' AS $$ SELECT CASE WHEN tier = 3 THEN 0.10 WHEN tier = 2 THEN 0.15 ELSE 0.20 END; $$;
CREATE OR REPLACE FUNCTION public.get_public_profiles(p_user_ids uuid[]) RETURNS TABLE(id uuid, name text, creator_tier integer) LANGUAGE sql STABLE SECURITY DEFINER SET search_path TO 'public' AS $$ SELECT p.id, p.name, p.creator_tier FROM public.profiles p WHERE p.id = ANY(p_user_ids); $$;
CREATE OR REPLACE FUNCTION public.deduct_energy(p_user_id uuid, p_cost integer) RETURNS integer LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$ DECLARE v_remaining integer; BEGIN IF p_cost <= 0 THEN SELECT energy INTO v_remaining FROM profiles WHERE id = p_user_id; RETURN COALESCE(v_remaining, 0); END IF; UPDATE profiles SET energy = energy - p_cost WHERE id = p_user_id AND energy >= p_cost RETURNING energy INTO v_remaining; IF v_remaining IS NULL THEN RETURN -1; END IF; RETURN v_remaining; END; $$;
CREATE OR REPLACE FUNCTION public.get_deck_stats(p_deck_id uuid) RETURNS TABLE(new_count bigint, learning_count bigint, review_count bigint, reviewed_today bigint, new_reviewed_today bigint, new_graduated_today bigint) LANGUAGE sql STABLE SET search_path TO 'public' AS $$ WITH deck_cards AS (SELECT id, state, scheduled_date FROM public.cards WHERE deck_id = p_deck_id), today_reviewed AS (SELECT DISTINCT rl.card_id FROM public.review_logs rl JOIN deck_cards dc ON dc.id = rl.card_id WHERE rl.reviewed_at::date = CURRENT_DATE AND dc.state = 2 AND dc.scheduled_date > now()), new_cards_studied AS (SELECT DISTINCT rl.card_id, dc.state FROM public.review_logs rl JOIN deck_cards dc ON dc.id = rl.card_id WHERE rl.reviewed_at::date = CURRENT_DATE AND NOT EXISTS (SELECT 1 FROM public.review_logs rl2 WHERE rl2.card_id = rl.card_id AND rl2.reviewed_at::date < CURRENT_DATE) AND dc.state IN (1, 2)) SELECT COUNT(*) FILTER (WHERE dc.state = 0), COUNT(*) FILTER (WHERE dc.state = 1), COUNT(*) FILTER (WHERE dc.state = 2 AND dc.scheduled_date <= now()), (SELECT COUNT(*) FROM today_reviewed), (SELECT COUNT(*) FROM new_cards_studied), (SELECT COUNT(*) FROM new_cards_studied WHERE state = 2) FROM deck_cards dc; $$;
CREATE OR REPLACE FUNCTION public.get_all_user_deck_stats(p_user_id uuid) RETURNS TABLE(deck_id uuid, new_count bigint, learning_count bigint, review_count bigint, reviewed_today bigint, new_reviewed_today bigint, new_graduated_today bigint) LANGUAGE sql STABLE SECURITY DEFINER SET search_path TO 'public' AS $$ WITH new_cards_studied AS (SELECT DISTINCT rl.card_id, c.state, c.deck_id FROM public.review_logs rl JOIN public.cards c ON c.id = rl.card_id JOIN public.decks d ON d.id = c.deck_id WHERE rl.reviewed_at::date = CURRENT_DATE AND d.user_id = p_user_id AND NOT EXISTS (SELECT 1 FROM public.review_logs rl2 WHERE rl2.card_id = rl.card_id AND rl2.reviewed_at::date < CURRENT_DATE) AND c.state IN (1, 2)) SELECT c.deck_id, COUNT(*) FILTER (WHERE c.state = 0), COUNT(*) FILTER (WHERE c.state = 1), COUNT(*) FILTER (WHERE c.state = 2 AND c.scheduled_date <= now()), COUNT(DISTINCT rt.card_id) FILTER (WHERE rt.card_id IS NOT NULL AND c.state = 2 AND c.scheduled_date > now()), (SELECT COUNT(*) FROM new_cards_studied ncs WHERE ncs.deck_id = c.deck_id), (SELECT COUNT(*) FROM new_cards_studied ncs WHERE ncs.deck_id = c.deck_id AND ncs.state = 2) FROM public.cards c JOIN public.decks d ON d.id = c.deck_id LEFT JOIN (SELECT DISTINCT card_id FROM public.review_logs WHERE reviewed_at::date = CURRENT_DATE) rt ON rt.card_id = c.id WHERE d.user_id = p_user_id GROUP BY c.deck_id; $$;
CREATE OR REPLACE FUNCTION public.delete_deck_cascade(p_deck_id uuid) RETURNS void LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$ DECLARE r RECORD; BEGIN IF NOT EXISTS (SELECT 1 FROM decks WHERE id = p_deck_id AND user_id = auth.uid()) THEN RAISE EXCEPTION 'Not authorized'; END IF; FOR r IN SELECT id FROM decks WHERE parent_deck_id = p_deck_id LOOP PERFORM delete_deck_cascade(r.id); END LOOP; DELETE FROM exam_questions WHERE card_id IN (SELECT id FROM cards WHERE deck_id = p_deck_id); DELETE FROM review_logs WHERE card_id IN (SELECT id FROM cards WHERE deck_id = p_deck_id); DELETE FROM turma_decks WHERE deck_id = p_deck_id; DELETE FROM exam_questions WHERE exam_id IN (SELECT id FROM exams WHERE deck_id = p_deck_id); DELETE FROM exams WHERE deck_id = p_deck_id; DELETE FROM marketplace_listings WHERE deck_id = p_deck_id; DELETE FROM cards WHERE deck_id = p_deck_id; DELETE FROM decks WHERE id = p_deck_id; END; $$;
CREATE OR REPLACE FUNCTION public.delete_folder_cascade(p_folder_id uuid) RETURNS void LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$ DECLARE r RECORD; BEGIN IF NOT EXISTS (SELECT 1 FROM folders WHERE id = p_folder_id AND user_id = auth.uid()) THEN RAISE EXCEPTION 'Not authorized'; END IF; FOR r IN SELECT id FROM folders WHERE parent_id = p_folder_id LOOP PERFORM delete_folder_cascade(r.id); END LOOP; FOR r IN SELECT id FROM decks WHERE folder_id = p_folder_id LOOP PERFORM delete_deck_cascade(r.id); END LOOP; DELETE FROM folders WHERE id = p_folder_id; END; $$;
CREATE OR REPLACE FUNCTION public.leave_turma(_turma_id uuid) RETURNS void LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$ DECLARE _user_id uuid; _user_role turma_role; _is_owner boolean; BEGIN _user_id := auth.uid(); IF _user_id IS NULL THEN RAISE EXCEPTION 'Not authenticated'; END IF; SELECT role INTO _user_role FROM turma_members WHERE turma_id = _turma_id AND user_id = _user_id; IF _user_role IS NULL THEN RAISE EXCEPTION 'Not a member'; END IF; SELECT (owner_id = _user_id) INTO _is_owner FROM turmas WHERE id = _turma_id; IF _is_owner THEN DELETE FROM turma_lesson_files WHERE turma_id = _turma_id; DELETE FROM turma_decks WHERE turma_id = _turma_id; DELETE FROM turma_exam_answers WHERE attempt_id IN (SELECT a.id FROM turma_exam_attempts a JOIN turma_exams e ON e.id = a.exam_id WHERE e.turma_id = _turma_id); DELETE FROM turma_exam_attempts WHERE exam_id IN (SELECT id FROM turma_exams WHERE turma_id = _turma_id); DELETE FROM turma_exam_questions WHERE exam_id IN (SELECT id FROM turma_exams WHERE turma_id = _turma_id); DELETE FROM turma_exams WHERE turma_id = _turma_id; DELETE FROM turma_questions WHERE turma_id = _turma_id; DELETE FROM turma_lessons WHERE turma_id = _turma_id; DELETE FROM turma_subjects WHERE turma_id = _turma_id; DELETE FROM turma_semesters WHERE turma_id = _turma_id; DELETE FROM turma_ratings WHERE turma_id = _turma_id; DELETE FROM turma_subscriptions WHERE turma_id = _turma_id; DELETE FROM turma_permissions WHERE turma_id = _turma_id; DELETE FROM turma_members WHERE turma_id = _turma_id; DELETE FROM turmas WHERE id = _turma_id; RETURN; END IF; DELETE FROM turma_members WHERE turma_id = _turma_id AND user_id = _user_id; END; $$;
CREATE OR REPLACE FUNCTION public.find_turma_by_invite_code(p_invite_code text) RETURNS TABLE(id uuid, name text, description text, is_private boolean, cover_image_url text, owner_id uuid, subscription_price numeric, avg_rating numeric, rating_count integer) LANGUAGE plpgsql STABLE SECURITY DEFINER SET search_path TO 'public' AS $$ BEGIN RETURN QUERY SELECT t.id, t.name, t.description, t.is_private, t.cover_image_url, t.owner_id, t.subscription_price, t.avg_rating, t.rating_count FROM turmas t WHERE t.invite_code = p_invite_code LIMIT 1; END; $$;
CREATE OR REPLACE FUNCTION public.process_marketplace_purchase(p_listing_id uuid) RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$ DECLARE v_buyer_id UUID; v_listing RECORD; v_buyer_balance NUMERIC; v_seller_tier INTEGER; v_fee NUMERIC; v_seller_amount NUMERIC; BEGIN v_buyer_id := auth.uid(); IF v_buyer_id IS NULL THEN RAISE EXCEPTION 'Not authenticated'; END IF; SELECT * INTO v_listing FROM marketplace_listings WHERE id = p_listing_id AND is_published = true FOR UPDATE; IF NOT FOUND THEN RAISE EXCEPTION 'Listing not found'; END IF; IF v_listing.seller_id = v_buyer_id THEN RAISE EXCEPTION 'Cannot buy own listing'; END IF; IF EXISTS (SELECT 1 FROM marketplace_purchases WHERE listing_id = p_listing_id AND buyer_id = v_buyer_id) THEN RAISE EXCEPTION 'Already purchased'; END IF; IF NOT v_listing.is_free THEN SELECT memocoins INTO v_buyer_balance FROM profiles WHERE id = v_buyer_id FOR UPDATE; IF v_buyer_balance < v_listing.price THEN RAISE EXCEPTION 'Insufficient balance'; END IF; UPDATE profiles SET memocoins = memocoins - v_listing.price WHERE id = v_buyer_id; INSERT INTO memocoin_transactions (user_id, amount, type, description, reference_id) VALUES (v_buyer_id, -v_listing.price, 'debit', 'Compra: ' || v_listing.title, p_listing_id); SELECT creator_tier INTO v_seller_tier FROM profiles WHERE id = v_listing.seller_id FOR UPDATE; v_fee := CASE WHEN v_seller_tier = 3 THEN 0.10 WHEN v_seller_tier = 2 THEN 0.15 ELSE 0.20 END; v_seller_amount := v_listing.price * (1 - v_fee); UPDATE profiles SET memocoins = memocoins + v_seller_amount WHERE id = v_listing.seller_id; INSERT INTO memocoin_transactions (user_id, amount, type, description, reference_id) VALUES (v_listing.seller_id, v_seller_amount, 'credit', format('Venda: %s (taxa %s%%)', v_listing.title, (v_fee * 100)::INTEGER), p_listing_id); END IF; INSERT INTO marketplace_purchases (listing_id, buyer_id, price_paid) VALUES (p_listing_id, v_buyer_id, CASE WHEN v_listing.is_free THEN 0 ELSE v_listing.price END); UPDATE marketplace_listings SET downloads = downloads + 1 WHERE id = p_listing_id; RETURN jsonb_build_object('success', true, 'deck_id', v_listing.deck_id); END; $$;
CREATE OR REPLACE FUNCTION public.process_turma_subscription(p_turma_id uuid) RETURNS jsonb LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$ DECLARE v_user_id UUID; v_turma RECORD; v_user_energy INTEGER; v_expires_at TIMESTAMPTZ; BEGIN v_user_id := auth.uid(); IF v_user_id IS NULL THEN RAISE EXCEPTION 'Not authenticated'; END IF; SELECT * INTO v_turma FROM turmas WHERE id = p_turma_id; IF NOT FOUND THEN RAISE EXCEPTION 'Community not found'; END IF; IF NOT is_turma_member(v_user_id, p_turma_id) THEN RAISE EXCEPTION 'Not a member'; END IF; IF EXISTS (SELECT 1 FROM turma_subscriptions WHERE turma_id = p_turma_id AND user_id = v_user_id AND expires_at > now()) THEN RAISE EXCEPTION 'Already subscribed'; END IF; IF v_turma.subscription_price > 0 THEN SELECT energy INTO v_user_energy FROM profiles WHERE id = v_user_id FOR UPDATE; IF v_user_energy < v_turma.subscription_price THEN RAISE EXCEPTION 'Insufficient credits'; END IF; UPDATE profiles SET energy = energy - v_turma.subscription_price WHERE id = v_user_id; UPDATE profiles SET energy = energy + v_turma.subscription_price WHERE id = v_turma.owner_id; INSERT INTO memocoin_transactions (user_id, amount, type, description, reference_id) VALUES (v_user_id, -v_turma.subscription_price, 'debit', 'Assinatura: ' || v_turma.name, p_turma_id); INSERT INTO memocoin_transactions (user_id, amount, type, description, reference_id) VALUES (v_turma.owner_id, v_turma.subscription_price, 'credit', 'Assinatura recebida: ' || v_turma.name, p_turma_id); END IF; UPDATE turma_members SET is_subscriber = true WHERE turma_id = p_turma_id AND user_id = v_user_id; v_expires_at := now() + interval '7 days'; INSERT INTO turma_subscriptions (turma_id, user_id, amount, started_at, expires_at) VALUES (p_turma_id, v_user_id, v_turma.subscription_price, now(), v_expires_at); RETURN jsonb_build_object('success', true, 'expires_at', v_expires_at); END; $$;
CREATE OR REPLACE FUNCTION public.restore_subscription_status(p_turma_id uuid) RETURNS boolean LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$ DECLARE v_user_id uuid; v_has_active boolean; BEGIN v_user_id := auth.uid(); IF v_user_id IS NULL THEN RETURN false; END IF; SELECT EXISTS (SELECT 1 FROM turma_subscriptions WHERE turma_id = p_turma_id AND user_id = v_user_id AND expires_at > now()) INTO v_has_active; IF v_has_active THEN UPDATE turma_members SET is_subscriber = true WHERE turma_id = p_turma_id AND user_id = v_user_id AND is_subscriber = false; RETURN true; END IF; RETURN false; END; $$;
CREATE OR REPLACE FUNCTION public.get_community_preview_stats(p_turma_id uuid) RETURNS jsonb LANGUAGE plpgsql STABLE SECURITY DEFINER SET search_path TO 'public' AS $$ DECLARE v_is_private boolean; v_subjects jsonb; v_root_lessons jsonb; BEGIN SELECT is_private INTO v_is_private FROM turmas WHERE id = p_turma_id; IF v_is_private AND NOT is_turma_member(auth.uid(), p_turma_id) THEN RETURN jsonb_build_object('subjects', '[]'::jsonb, 'rootLessons', '[]'::jsonb); END IF; SELECT COALESCE(jsonb_agg(sub ORDER BY sub.sort_order), '[]'::jsonb) INTO v_subjects FROM (SELECT s.id, s.name, s.sort_order, (SELECT COUNT(*) FROM turma_lessons l WHERE l.subject_id = s.id AND l.is_published = true) AS "lessonCount", (SELECT COALESCE(COUNT(*), 0) FROM cards c JOIN turma_decks td ON td.deck_id = c.deck_id WHERE td.subject_id = s.id AND td.turma_id = p_turma_id) AS "cardCount", (SELECT COALESCE(COUNT(*), 0) FROM turma_lesson_files f JOIN turma_lessons l2 ON l2.id = f.lesson_id WHERE l2.subject_id = s.id AND f.turma_id = p_turma_id) AS "fileCount" FROM turma_subjects s WHERE s.turma_id = p_turma_id) sub; SELECT COALESCE(jsonb_agg(jsonb_build_object('id', l.id, 'name', l.name) ORDER BY l.sort_order), '[]'::jsonb) INTO v_root_lessons FROM turma_lessons l WHERE l.turma_id = p_turma_id AND l.subject_id IS NULL AND l.is_published = true; RETURN jsonb_build_object('subjects', v_subjects, 'rootLessons', v_root_lessons); END; $$;
CREATE OR REPLACE FUNCTION public.get_community_full_preview(p_turma_id uuid) RETURNS jsonb LANGUAGE plpgsql STABLE SECURITY DEFINER SET search_path TO 'public' AS $$ DECLARE v_turma RECORD; v_subjects jsonb; v_lessons jsonb; v_exams jsonb; v_members jsonb; v_member_count integer; BEGIN SELECT * INTO v_turma FROM turmas WHERE id = p_turma_id; IF NOT FOUND THEN RETURN '{}'::jsonb; END IF; IF v_turma.is_private AND NOT is_turma_member(auth.uid(), p_turma_id) THEN RETURN jsonb_build_object('restricted', true); END IF; SELECT COALESCE(jsonb_agg(jsonb_build_object('id', s.id, 'name', s.name, 'parent_id', s.parent_id, 'sort_order', s.sort_order) ORDER BY s.sort_order), '[]'::jsonb) INTO v_subjects FROM turma_subjects s WHERE s.turma_id = p_turma_id; SELECT COALESCE(jsonb_agg(jsonb_build_object('id', l.id, 'name', l.name, 'subject_id', l.subject_id, 'lesson_date', l.lesson_date, 'sort_order', l.sort_order) ORDER BY l.sort_order), '[]'::jsonb) INTO v_lessons FROM turma_lessons l WHERE l.turma_id = p_turma_id AND l.is_published = true; SELECT COALESCE(jsonb_agg(jsonb_build_object('id', e.id, 'title', e.title, 'subject_id', e.subject_id, 'total_questions', e.total_questions, 'time_limit_seconds', e.time_limit_seconds) ORDER BY e.created_at DESC), '[]'::jsonb) INTO v_exams FROM turma_exams e WHERE e.turma_id = p_turma_id AND e.is_published = true; SELECT COUNT(*) INTO v_member_count FROM turma_members WHERE turma_id = p_turma_id; SELECT COALESCE(jsonb_agg(jsonb_build_object('name', p.name, 'role', m.role) ORDER BY m.role, m.joined_at), '[]'::jsonb) INTO v_members FROM (SELECT * FROM turma_members WHERE turma_id = p_turma_id ORDER BY role, joined_at LIMIT 20) m JOIN profiles p ON p.id = m.user_id; RETURN jsonb_build_object('subjects', v_subjects, 'lessons', v_lessons, 'exams', v_exams, 'members', v_members, 'member_count', v_member_count); END; $$;
CREATE OR REPLACE FUNCTION public.update_listing_rating() RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$ BEGIN UPDATE public.marketplace_listings SET avg_rating = (SELECT COALESCE(AVG(rating), 0) FROM public.deck_reviews WHERE listing_id = COALESCE(NEW.listing_id, OLD.listing_id)), rating_count = (SELECT COUNT(*) FROM public.deck_reviews WHERE listing_id = COALESCE(NEW.listing_id, OLD.listing_id)) WHERE id = COALESCE(NEW.listing_id, OLD.listing_id); RETURN COALESCE(NEW, OLD); END; $$;
CREATE OR REPLACE FUNCTION public.update_feature_vote_count() RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$ BEGIN UPDATE public.feature_requests SET vote_count = (SELECT COUNT(*) FROM public.feature_votes WHERE feature_id = COALESCE(NEW.feature_id, OLD.feature_id)) WHERE id = COALESCE(NEW.feature_id, OLD.feature_id); RETURN COALESCE(NEW, OLD); END; $$;
CREATE OR REPLACE FUNCTION public.update_turma_rating() RETURNS trigger LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$ BEGIN UPDATE public.turmas SET avg_rating = (SELECT COALESCE(AVG(rating), 0) FROM public.turma_ratings WHERE turma_id = COALESCE(NEW.turma_id, OLD.turma_id)), rating_count = (SELECT COUNT(*) FROM public.turma_ratings WHERE turma_id = COALESCE(NEW.turma_id, OLD.turma_id)) WHERE id = COALESCE(NEW.turma_id, OLD.turma_id); RETURN COALESCE(NEW, OLD); END; $$;
CREATE OR REPLACE FUNCTION public.admin_get_profiles(p_search text DEFAULT '', p_limit integer DEFAULT 50, p_offset integer DEFAULT 0) RETURNS TABLE(id uuid, name text, email text, energy integer, memocoins numeric, creator_tier integer, is_banned boolean, created_at timestamptz, daily_cards_studied integer, successful_cards_counter integer, onboarding_completed boolean) LANGUAGE plpgsql STABLE SECURITY DEFINER SET search_path TO 'public' AS $$ BEGIN IF NOT has_role(auth.uid(), 'admin') THEN RAISE EXCEPTION 'Not authorized'; END IF; RETURN QUERY SELECT p.id, p.name, p.email, p.energy, p.memocoins, p.creator_tier, p.is_banned, p.created_at, p.daily_cards_studied, p.successful_cards_counter, p.onboarding_completed FROM profiles p WHERE (p_search = '' OR p.name ILIKE '%' || p_search || '%' OR p.email ILIKE '%' || p_search || '%') ORDER BY p.created_at DESC LIMIT p_limit OFFSET p_offset; END; $$;
CREATE OR REPLACE FUNCTION public.admin_get_user_decks(p_user_id uuid) RETURNS TABLE(id uuid, name text, created_at timestamptz, is_archived boolean, card_count bigint) LANGUAGE plpgsql STABLE SECURITY DEFINER SET search_path TO 'public' AS $$ BEGIN IF NOT has_role(auth.uid(), 'admin') THEN RAISE EXCEPTION 'Not authorized'; END IF; RETURN QUERY SELECT d.id, d.name, d.created_at, d.is_archived, (SELECT COUNT(*) FROM cards c WHERE c.deck_id = d.id) AS card_count FROM decks d WHERE d.user_id = p_user_id ORDER BY d.created_at DESC; END; $$;
CREATE OR REPLACE FUNCTION public.admin_get_user_study_history(p_user_id uuid, p_days integer DEFAULT 90) RETURNS TABLE(study_date date, cards_reviewed bigint, avg_rating numeric) LANGUAGE plpgsql STABLE SECURITY DEFINER SET search_path TO 'public' AS $$ BEGIN IF NOT has_role(auth.uid(), 'admin') THEN RAISE EXCEPTION 'Not authorized'; END IF; RETURN QUERY SELECT (r.reviewed_at AT TIME ZONE 'UTC')::date AS study_date, COUNT(*) AS cards_reviewed, ROUND(AVG(r.rating), 2) AS avg_rating FROM review_logs r WHERE r.user_id = p_user_id AND r.reviewed_at >= now() - (p_days || ' days')::interval GROUP BY study_date ORDER BY study_date DESC; END; $$;
CREATE OR REPLACE FUNCTION public.admin_get_user_token_usage(p_user_id uuid, p_days integer DEFAULT 30) RETURNS TABLE(feature_key text, model text, total_calls bigint, total_prompt_tokens bigint, total_completion_tokens bigint, total_tokens_sum bigint, total_energy_cost bigint) LANGUAGE plpgsql STABLE SECURITY DEFINER SET search_path TO 'public' AS $$ BEGIN IF NOT has_role(auth.uid(), 'admin') THEN RAISE EXCEPTION 'Not authorized'; END IF; RETURN QUERY SELECT t.feature_key, t.model, COUNT(*), SUM(t.prompt_tokens)::bigint, SUM(t.completion_tokens)::bigint, SUM(t.total_tokens)::bigint, SUM(t.energy_cost)::bigint FROM ai_token_usage t WHERE t.user_id = p_user_id AND t.created_at >= now() - (p_days || ' days')::interval GROUP BY t.feature_key, t.model ORDER BY 6 DESC; END; $$;
CREATE OR REPLACE FUNCTION public.admin_update_profile(p_user_id uuid, p_name text DEFAULT NULL, p_energy integer DEFAULT NULL, p_memocoins numeric DEFAULT NULL, p_is_banned boolean DEFAULT NULL) RETURNS void LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public' AS $$ BEGIN IF NOT has_role(auth.uid(), 'admin') THEN RAISE EXCEPTION 'Not authorized'; END IF; UPDATE profiles SET name = COALESCE(p_name, name), energy = COALESCE(p_energy, energy), memocoins = COALESCE(p_memocoins, memocoins), is_banned = COALESCE(p_is_banned, is_banned), updated_at = now() WHERE id = p_user_id; END; $$;

-- RLS POLICIES
CREATE POLICY "Users can view own profile" ON public.profiles FOR SELECT USING (auth.uid() = id);
CREATE POLICY "Users can update own profile" ON public.profiles FOR UPDATE USING (auth.uid() = id);
CREATE POLICY "Users can insert own profile" ON public.profiles FOR INSERT WITH CHECK (auth.uid() = id);
CREATE POLICY "Users can view own roles" ON public.user_roles FOR SELECT USING (auth.uid() = user_id);
CREATE POLICY "Admins can manage roles" ON public.user_roles FOR ALL USING (has_role(auth.uid(), 'admin'));
CREATE POLICY "Users can view own folders" ON public.folders FOR SELECT USING (auth.uid() = user_id);
CREATE POLICY "Users can insert own folders" ON public.folders FOR INSERT WITH CHECK (auth.uid() = user_id);
CREATE POLICY "Users can update own folders" ON public.folders FOR UPDATE USING (auth.uid() = user_id);
CREATE POLICY "Users can delete own folders" ON public.folders FOR DELETE USING (auth.uid() = user_id);
CREATE POLICY "Users can view own decks" ON public.decks FOR SELECT USING (auth.uid() = user_id);
CREATE POLICY "Users can insert own decks" ON public.decks FOR INSERT WITH CHECK (auth.uid() = user_id);
CREATE POLICY "Users can update own decks" ON public.decks FOR UPDATE USING (auth.uid() = user_id);
