DROP TRIGGER IF EXISTS update_turma_subjects_updated_at ON public.turma_subjects;
CREATE TRIGGER update_turma_subjects_updated_at BEFORE UPDATE ON public.turma_subjects FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();
DROP TRIGGER IF EXISTS update_turma_lessons_updated_at ON public.turma_lessons;
CREATE TRIGGER update_turma_lessons_updated_at BEFORE UPDATE ON public.turma_lessons FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();
DROP TRIGGER IF EXISTS update_turma_exams_updated_at ON public.turma_exams;
