CREATE TRIGGER update_ai_conversations_updated_at BEFORE UPDATE ON public.ai_conversations FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();
DROP TRIGGER IF EXISTS update_user_missions_updated_at ON public.user_missions;
CREATE TRIGGER update_user_missions_updated_at BEFORE UPDATE ON public.user_missions FOR EACH ROW EXECUTE FUNCTION public.update_updated_at_column();
