-- Storage policies
DROP POLICY IF EXISTS "Public read card images" ON storage.objects;
CREATE POLICY "Public read card images" ON storage.objects FOR SELECT USING (bucket_id = 'card-images');
DROP POLICY IF EXISTS "Auth users upload card images" ON storage.objects;
CREATE POLICY "Auth users upload card images" ON storage.objects FOR INSERT WITH CHECK (bucket_id = 'card-images' AND auth.uid() IS NOT NULL);
DROP POLICY IF EXISTS "Public read community covers" ON storage.objects;
CREATE POLICY "Public read community covers" ON storage.objects FOR SELECT USING (bucket_id = 'community-covers');
DROP POLICY IF EXISTS "Auth users upload community covers" ON storage.objects;
CREATE POLICY "Auth users upload community covers" ON storage.objects FOR INSERT WITH CHECK (bucket_id = 'community-covers' AND auth.uid() IS NOT NULL);
DROP POLICY IF EXISTS "Public read lesson files" ON storage.objects;
CREATE POLICY "Public read lesson files" ON storage.objects FOR SELECT USING (bucket_id = 'lesson-files');
DROP POLICY IF EXISTS "Auth users upload lesson files" ON storage.objects;
CREATE POLICY "Auth users upload lesson files" ON storage.objects FOR INSERT WITH CHECK (bucket_id = 'lesson-files' AND auth.uid() IS NOT NULL);
